mapper.select:
select id, product_id as productId, original_price as originalPrice, offer_price as offerPrice, stock, start_time as startTime, end_time as endTime, status, create_time as createTime, update_time as updateTime, create_user as createUser, update_user as updateUser
from special_offer
where id = #{id}

select id, product_id as productId, original_price as originalPrice, offer_price as offerPrice, stock, start_time as startTime, end_time as endTime, status, create_time as createTime, update_time as updateTime, create_user as createUser, update_user as updateUser
from special_offer

    and product_id = #{productId}
    and status = #{status}

order by id desc
limit #{page}, #{pageSize}

